import csv
import io
import threading
from dataclasses import dataclass, field, replace as _dc_replace
from datetime import datetime
from enum import Enum
from typing import List, Optional


# ===========================================================================
# Enums
# ===========================================================================

class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ===========================================================================
# Exceptions
# ===========================================================================

class TeamCollaborationError(Exception):
    pass


class ValidationError(TeamCollaborationError):
    pass


class NotFoundError(TeamCollaborationError):
    pass


class AuthorizationError(TeamCollaborationError):
    pass


class DuplicateError(TeamCollaborationError):
    pass


class ConflictError(TeamCollaborationError):
    pass


# ===========================================================================
# Dataclasses
# ===========================================================================

@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ===========================================================================
# Internal utilities
# ===========================================================================

def _valid_email(email):
    """Return True if email has non-empty local and domain parts."""
    if not email:
        return False
    idx = email.find("@")
    if idx < 1:
        return False
    return idx < len(email) - 1


# Fast-clone helpers: all fields on these dataclasses are immutable
# (int, str, Enum, datetime, Optional[immutable]), so a shallow field-copy
# is fully isolated from the internal store.
def _clone_user(u):
    return _dc_replace(u)

def _clone_project(p):
    return _dc_replace(p)

def _clone_task(t):
    return _dc_replace(t)

def _clone_rating(r):
    return _dc_replace(r)

# Message has an `attachments` list that callers may mutate, so give each
# returned copy its own list.  Attachment instances have only immutable fields,
# so sharing the objects themselves is safe.
def _clone_message(m):
    return _dc_replace(m, attachments=list(m.attachments))


class _IDCounter:
    """Global ID sequence; must be incremented under the shared lock."""
    def __init__(self):
        self._value = 0

    def next(self):
        self._value += 1
        return self._value


