# Store classes
# ===========================================================================

class _UserStore:
    def __init__(self, lock, counter):
        self._lock = lock
        self._counter = counter
        self._users = {}
        self._by_username = {}
        self._by_email = {}

    def register(self, username, email, role, now):
        if not username or not username.strip():
            raise ValidationError("Username cannot be empty or whitespace")
        if not _valid_email(email):
            raise ValidationError("Invalid email: {0}".format(email))
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole instance")
        if username in self._by_username:
            raise DuplicateError("Username already registered: {0}".format(username))
        if email in self._by_email:
            raise DuplicateError("Email already registered: {0}".format(email))
        uid = self._counter.next()
        user = User(id=uid, username=username, email=email, role=role, created_at=now)
        self._users[uid] = user
        self._by_username[username] = uid
        self._by_email[email] = uid
        return _clone_user(user)

    def get(self, user_id):
        if user_id not in self._users:
            raise NotFoundError("User not found: {0}".format(user_id))
        return _clone_user(self._users[user_id])

    def list_all(self):
        return [_clone_user(u) for u in sorted(self._users.values(), key=lambda u: u.id)]

    def update(self, user_id, username=None, email=None, role=None):
        if user_id not in self._users:
            raise NotFoundError("User not found: {0}".format(user_id))
        user = self._users[user_id]
        if username is not None:
            if username != user.username and username in self._by_username:
                raise DuplicateError("Username already taken: {0}".format(username))
        if email is not None:
            if not _valid_email(email):
                raise ValidationError("Invalid email: {0}".format(email))
            if email != user.email and email in self._by_email:
                raise DuplicateError("Email already taken: {0}".format(email))
        if role is not None and not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole instance")
        if username is not None and username != user.username:
            del self._by_username[user.username]
            self._by_username[username] = user_id
            user.username = username
        if email is not None and email != user.email:
            del self._by_email[user.email]
            self._by_email[email] = user_id
            user.email = email
        if role is not None:
            user.role = role
        return _clone_user(user)

    def delete(self, user_id):
        user = self._users.pop(user_id)
        self._by_username.pop(user.username, None)
        self._by_email.pop(user.email, None)

    def exists(self, user_id):
        return user_id in self._users


class _ProjectStore:
    def __init__(self, lock, counter):
        self._lock = lock
        self._counter = counter
        self._projects = {}

    def create(self, name, start_date, end_date, owner_id, description):
        if not name:
            raise ValidationError("Project name cannot be empty")
        if end_date < start_date:
            raise ValidationError("end_date must be >= start_date")
        pid = self._counter.next()
        project = Project(
            id=pid,
            name=name,
            description=description,
            start_date=start_date,
            end_date=end_date,
            owner_id=owner_id,
        )
        self._projects[pid] = project
        return _clone_project(project)

    def get(self, project_id):
        if project_id not in self._projects:
            raise NotFoundError("Project not found: {0}".format(project_id))
        return _clone_project(self._projects[project_id])

    def get_raw(self, project_id):
        return self._projects.get(project_id)

    def list_all(self):
        return [_clone_project(p) for p in sorted(self._projects.values(), key=lambda p: p.id)]

    def update(self, project_id, name=None, description=None, start_date=None, end_date=None):
        if project_id not in self._projects:
            raise NotFoundError("Project not found: {0}".format(project_id))
        project = self._projects[project_id]
        if name is not None and not name:
            raise ValidationError("Project name cannot be empty")
        new_start = start_date if start_date is not None else project.start_date
        new_end = end_date if end_date is not None else project.end_date
        if new_end < new_start:
            raise ValidationError("end_date must be >= start_date")
        if name is not None:
            project.name = name
        if description is not None:
            project.description = description
        project.start_date = new_start
        project.end_date = new_end
        return _clone_project(project)

    def delete(self, project_id):
        del self._projects[project_id]

    def exists(self, project_id):
        return project_id in self._projects

    def find_by_owner(self, owner_id):
        return [p for p in self._projects.values() if p.owner_id == owner_id]


class _TaskStore:
    def __init__(self, lock, counter):
        self._lock = lock
        self._counter = counter
        self._tasks = {}
        self._by_project = {}
        self._by_assignee = {}

    def create(self, project_id, title, assignee_id, deadline, now):
        tid = self._counter.next()
        task = Task(
            id=tid,
            project_id=project_id,
            title=title,
            status=TaskStatus.NOT_STARTED,
            assignee_id=assignee_id,
            deadline=deadline,
            started_at=None,
            completed_at=None,
            created_at=now,
        )
        self._tasks[tid] = task
        self._by_project.setdefault(project_id, set()).add(tid)
        if assignee_id is not None:
            self._by_assignee.setdefault(assignee_id, set()).add(tid)
        return _clone_task(task)

    def get(self, task_id):
        if task_id not in self._tasks:
            raise NotFoundError("Task not found: {0}".format(task_id))
        return _clone_task(self._tasks[task_id])

    def list_by_project(self, project_id):
        ids = self._by_project.get(project_id, set())
        return [_clone_task(self._tasks[tid]) for tid in sorted(ids) if tid in self._tasks]

    def list_by_assignee(self, assignee_id):
        ids = self._by_assignee.get(assignee_id, set())
        return [_clone_task(self._tasks[tid]) for tid in sorted(ids) if tid in self._tasks]

    def assign(self, task_id, assignee_id):
        task = self._tasks[task_id]
        old = task.assignee_id
        if old is not None:
            self._by_assignee.get(old, set()).discard(task_id)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self._by_assignee.setdefault(assignee_id, set()).add(task_id)
        return _clone_task(task)

    def set_deadline(self, task_id, deadline):
        task = self._tasks[task_id]
        task.deadline = deadline
        return _clone_task(task)

    def update_status(self, task_id, status, now):
        task = self._tasks[task_id]
        if status == TaskStatus.IN_PROGRESS:
            if task.started_at is None:
                task.started_at = now
            task.completed_at = None
        elif status == TaskStatus.COMPLETED:
            if task.started_at is None:
                task.started_at = now
            task.completed_at = now
        else:
            task.started_at = None
            task.completed_at = None
        task.status = status
        return _clone_task(task)

    def exists(self, task_id):
        return task_id in self._tasks

    def delete_by_project(self, project_id):
        ids = list(self._by_project.pop(project_id, set()))
        for tid in ids:
            task = self._tasks.pop(tid, None)
            if task is not None and task.assignee_id is not None:
                self._by_assignee.get(task.assignee_id, set()).discard(tid)

    def get_tasks_for_assignee_raw(self, assignee_id):
        ids = self._by_assignee.get(assignee_id, set())
        return [self._tasks[tid] for tid in ids if tid in self._tasks]

    def get_tasks_for_project_raw(self, project_id):
        ids = self._by_project.get(project_id, set())
        return [self._tasks[tid] for tid in ids if tid in self._tasks]

    def all_tasks_raw(self):
        return list(self._tasks.values())


class _MessageStore:
    def __init__(self, lock, counter):
        self._lock = lock
        self._counter = counter
        self._messages = {}
        self._by_project = {}
        self._by_task = {}

    def post(self, author_id, body, project_id, task_id, parent_id, attachments_data, now):
        attachments = []
        for fname, data in (attachments_data or []):
            attachments.append(Attachment(
                filename=fname,
                size=len(data),
                uploaded_by=author_id,
                uploaded_at=now,
            ))
        mid = self._counter.next()
        msg = Message(
            id=mid,
            author_id=author_id,
            body=body,
            project_id=project_id,
            task_id=task_id,
            parent_id=parent_id,
            attachments=attachments,
            created_at=now,
            edited_at=None,
        )
        self._messages[mid] = msg
        if project_id is not None:
            self._by_project.setdefault(project_id, []).append(mid)
        if task_id is not None:
            self._by_task.setdefault(task_id, []).append(mid)
        return _clone_message(msg)

    def get(self, msg_id):
        if msg_id not in self._messages:
            raise NotFoundError("Message not found: {0}".format(msg_id))
        return _clone_message(self._messages[msg_id])

    def edit(self, msg_id, new_body, now):
        msg = self._messages[msg_id]
        msg.body = new_body
        msg.edited_at = now
        return _clone_message(msg)

    def add_attachment(self, msg_id, uploaded_by, filename, data, now):
        msg = self._messages[msg_id]
        msg.attachments.append(Attachment(
            filename=filename,
            size=len(data),
            uploaded_by=uploaded_by,
            uploaded_at=now,
        ))
        return _clone_message(msg)

    def list_by_project(self, project_id):
        ids = self._by_project.get(project_id, [])
        return [_clone_message(self._messages[mid]) for mid in sorted(ids) if mid in self._messages]

    def list_by_task(self, task_id):
        ids = self._by_task.get(task_id, [])
        return [_clone_message(self._messages[mid]) for mid in sorted(ids) if mid in self._messages]

    def delete(self, msg_id):
        msg = self._messages.pop(msg_id)
        if msg.project_id is not None:
            lst = self._by_project.get(msg.project_id, [])
            try:
                lst.remove(msg_id)
            except ValueError:
                pass
        if msg.task_id is not None:
            lst = self._by_task.get(msg.task_id, [])
            try:
                lst.remove(msg_id)
            except ValueError:
                pass

    def delete_by_project(self, project_id):
        ids = self._by_project.pop(project_id, [])
        for mid in ids:
            self._messages.pop(mid, None)

    def exists(self, msg_id):
        return msg_id in self._messages


