def _make_pdf(text_lines):
    """Build a minimal well-formed single-page PDF (ASCII bytes)."""

    def pdf_safe(s):
        result = []
        for c in str(s):
            if ord(c) >= 128:
                result.append("?")
            elif c == "\\":
                result.append("\\\\")
            elif c == "(":
                result.append("\\(")
            elif c == ")":
                result.append("\\)")
            else:
                result.append(c)
        return "".join(result)

    stream_lines = ["BT", "/F1 10 Tf", "50 750 Td"]
    for line in text_lines[:20]:
        stream_lines.append("({0}) Tj".format(pdf_safe(str(line)[:60])))
        stream_lines.append("0 -14 Td")
    stream_lines.append("ET")
    stream_body = "\n".join(stream_lines) + "\n"
    stream_len = len(stream_body.encode("ascii"))

    o1 = "1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n"
    o2 = "2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n"
    o3 = ("3 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
          "/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>\nendobj\n")
    o4 = ("4 0 obj\n<< /Length {0} >>\nstream\n{1}endstream\nendobj\n"
          .format(stream_len, stream_body))
    o5 = "5 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n"

    header = "%PDF-1.4\n"
    body = header + o1 + o2 + o3 + o4 + o5

    pos = len(header.encode("ascii"))
    offsets = []
    for obj_str in [o1, o2, o3, o4, o5]:
        offsets.append(pos)
        pos += len(obj_str.encode("ascii"))

    xref_pos = pos

    xref_lines = ["xref", "0 6", "0000000000 65535 f "]
    for off in offsets:
        xref_lines.append("{0:010d} 00000 n ".format(off))
    xref = "\n".join(xref_lines) + "\n"

    trailer = ("trailer\n<< /Size 6 /Root 1 0 R >>\nstartxref\n{0}\n%%EOF\n"
               .format(xref_pos))

    full = body + xref + trailer
    return full.encode("ascii")


