class TeamCollaborationManager:
    def __init__(self, now=None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._counter = _IDCounter()

        self.users = _UserStore(self._lock, self._counter)
        self.projects = _ProjectStore(self._lock, self._counter)
        self.tasks = _TaskStore(self._lock, self._counter)
        self.messages = _MessageStore(self._lock, self._counter)
        self.performance = _PerformanceStore(self._lock, self._counter)
        self.reports = _ReportsEngine(self._lock)

    # -----------------------------------------------------------------------
    # Users
    # -----------------------------------------------------------------------

    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            return self.users.register(username, email, role, self._now())

    def get_user(self, user_id):
        with self._lock:
            return self.users.get(user_id)

    def list_users(self):
        with self._lock:
            return self.users.list_all()

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            return self.users.update(user_id, username, email, role)

    def delete_user(self, user_id):
        with self._lock:
            if not self.users.exists(user_id):
                raise NotFoundError("User not found: {0}".format(user_id))
            if self.projects.find_by_owner(user_id):
                raise ConflictError("User owns projects, cannot delete")
            open_tasks = [
                t for t in self.tasks.get_tasks_for_assignee_raw(user_id)
                if t.status != TaskStatus.COMPLETED
            ]
            if open_tasks:
                raise ConflictError("User has open tasks, cannot delete")
            self.users.delete(user_id)

    # -----------------------------------------------------------------------
    # Projects
    # -----------------------------------------------------------------------

    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not self.users.exists(owner_id):
                raise NotFoundError("Owner not found: {0}".format(owner_id))
            return self.projects.create(name, start_date, end_date, owner_id, description)

    def get_project(self, project_id):
        with self._lock:
            return self.projects.get(project_id)

    def list_projects(self):
        with self._lock:
            return self.projects.list_all()

    def update_project(self, project_id, name=None, description=None,
                       start_date=None, end_date=None):
        with self._lock:
            return self.projects.update(project_id, name, description, start_date, end_date)

    def delete_project(self, project_id):
        with self._lock:
            if not self.projects.exists(project_id):
                raise NotFoundError("Project not found: {0}".format(project_id))
            self.tasks.delete_by_project(project_id)
            self.messages.delete_by_project(project_id)
            self.projects.delete(project_id)

    # -----------------------------------------------------------------------
    # Tasks
    # -----------------------------------------------------------------------

    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            if not self.projects.exists(project_id):
                raise NotFoundError("Project not found: {0}".format(project_id))
            if assignee_id is not None and not self.users.exists(assignee_id):
                raise NotFoundError("Assignee not found: {0}".format(assignee_id))
            if not title:
                raise ValidationError("Task title cannot be empty")
            project = self.projects.get_raw(project_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("Deadline before project start date")
            return self.tasks.create(project_id, title, assignee_id, deadline, self._now())

    def get_task(self, task_id):
        with self._lock:
            return self.tasks.get(task_id)

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if not self.projects.exists(project_id):
                raise NotFoundError("Project not found: {0}".format(project_id))
            return self.tasks.list_by_project(project_id)

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            if not self.users.exists(user_id):
                raise NotFoundError("User not found: {0}".format(user_id))
            return self.tasks.list_by_assignee(user_id)

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found: {0}".format(task_id))
            if not self.users.exists(assignee_id):
                raise NotFoundError("User not found: {0}".format(assignee_id))
            return self.tasks.assign(task_id, assignee_id)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found: {0}".format(task_id))
            if not self.users.exists(new_assignee_id):
                raise NotFoundError("User not found: {0}".format(new_assignee_id))
            return self.tasks.assign(task_id, new_assignee_id)

    def unassign_task(self, task_id):
        with self._lock:
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found: {0}".format(task_id))
            return self.tasks.assign(task_id, None)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found: {0}".format(task_id))
            if deadline is not None:
                task_raw = self.tasks._tasks[task_id]
                project_raw = self.projects.get_raw(task_raw.project_id)
                if deadline < project_raw.start_date:
                    raise ValidationError("Deadline before project start date")
            return self.tasks.set_deadline(task_id, deadline)

    def update_status(self, task_id, status):
        with self._lock:
            if not self.tasks.exists(task_id):
                raise NotFoundError("Task not found: {0}".format(task_id))
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus instance")
            return self.tasks.update_status(task_id, status, self._now())

    # -----------------------------------------------------------------------
    # Messaging
    # -----------------------------------------------------------------------

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        with self._lock:
            if not self.users.exists(author_id):
                raise NotFoundError("Author not found: {0}".format(author_id))
            if project_id is None and task_id is None:
                raise ValidationError("Provide exactly one of project_id or task_id")
            if project_id is not None and task_id is not None:
                raise ValidationError("Provide exactly one of project_id or task_id, not both")
            if project_id is not None and not self.projects.exists(project_id):
                raise NotFoundError("Project not found: {0}".format(project_id))
            if task_id is not None and not self.tasks.exists(task_id):
                raise NotFoundError("Task not found: {0}".format(task_id))
            if parent_id is not None and not self.messages.exists(parent_id):
                raise NotFoundError("Parent message not found: {0}".format(parent_id))
            if not body and not attachments:
                raise ValidationError("Body cannot be empty without attachments")
            return self.messages.post(
                author_id, body, project_id, task_id, parent_id, attachments, self._now()
            )

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            if not self.messages.exists(message_id):
                raise NotFoundError("Message not found: {0}".format(message_id))
            msg_raw = self.messages._messages[message_id]
            if editor_id != msg_raw.author_id:
                raise AuthorizationError("Only the author can edit this message")
            if not new_body and not msg_raw.attachments:
                raise ValidationError("Body cannot be empty without attachments")
            return self.messages.edit(message_id, new_body, self._now())

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            if not self.messages.exists(message_id):
                raise NotFoundError("Message not found: {0}".format(message_id))
            msg_raw = self.messages._messages[message_id]
