    # -----------------------------------------------------------------------
    # Performance
    # -----------------------------------------------------------------------

    def get_completion_rate(self, user_id):
        with self._lock:
            if not self.users.exists(user_id):
                raise NotFoundError("User not found: {0}".format(user_id))
            user_tasks = self.tasks.get_tasks_for_assignee_raw(user_id)
            if not user_tasks:
                return 0.0
            completed = sum(1 for t in user_tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(user_tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            if not self.users.exists(user_id):
                raise NotFoundError("User not found: {0}".format(user_id))
            done = [
                t for t in self.tasks.get_tasks_for_assignee_raw(user_id)
                if t.status == TaskStatus.COMPLETED and t.started_at and t.completed_at
            ]
            if not done:
                return None
            times = [(t.completed_at - t.started_at).total_seconds() for t in done]
            return sum(times) / len(times)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if not self.users.exists(rater_id):
                raise NotFoundError("Rater not found: {0}".format(rater_id))
            if not self.users.exists(ratee_id):
                raise NotFoundError("Ratee not found: {0}".format(ratee_id))
            if task_id is not None and not self.tasks.exists(task_id):
                raise NotFoundError("Task not found: {0}".format(task_id))
            if rater_id == ratee_id:
                raise ConflictError("Cannot rate yourself")
            if not (1 <= score <= 5):
                raise ValidationError("Score must be between 1 and 5 inclusive")
            return self.performance.add_rating(
                rater_id, ratee_id, score, feedback, task_id, self._now()
            )

    def get_ratings_summary(self, user_id):
        with self._lock:
            if not self.users.exists(user_id):
                raise NotFoundError("User not found: {0}".format(user_id))
            ratings = self.performance.get_ratings_for(user_id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count > 0 else 0.0
            return {"count": count, "average": average, "ratings": ratings}

    def get_user_dashboard(self, user_id):
        with self._lock:
            if not self.users.exists(user_id):
                raise NotFoundError("User not found: {0}".format(user_id))
            user_tasks = self.tasks.get_tasks_for_assignee_raw(user_id)
            total = len(user_tasks)
            completed = sum(1 for t in user_tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in user_tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in user_tasks if t.status == TaskStatus.NOT_STARTED)
            rate = completed / total if total > 0 else 0.0

            done = [
                t for t in user_tasks
                if t.status == TaskStatus.COMPLETED and t.started_at and t.completed_at
            ]
            avg_time = None
            if done:
                times = [(t.completed_at - t.started_at).total_seconds() for t in done]
                avg_time = sum(times) / len(times)

            ratings = self.performance.get_ratings_for(user_id)
            r_count = len(ratings)
            r_avg = sum(r.score for r in ratings) / r_count if r_count > 0 else 0.0

            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": rate,
                "average_completion_time": avg_time,
                "rating_count": r_count,
                "rating_average": r_avg,
            }

