    def project_progress_report(self, project_id):
        with self._lock:
            if not self.projects.exists(project_id):
                raise NotFoundError("Project not found: {0}".format(project_id))
            tasks = self.tasks.get_tasks_for_project_raw(project_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            rate = completed / total if total > 0 else 0.0

            now = self._now()
            overdue = sum(
                1 for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee = {}
            for t in tasks:
                if t.assignee_id is not None:
                    uid = t.assignee_id
                    if uid not in per_assignee:
                        per_assignee[uid] = {"total": 0, "completed": 0}
                    per_assignee[uid]["total"] += 1
                    if t.status == TaskStatus.COMPLETED:
                        per_assignee[uid]["completed"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "total_tasks": total,
                "status_counts": {
                    TaskStatus.NOT_STARTED.value: not_started,
                    TaskStatus.IN_PROGRESS.value: in_progress,
                    TaskStatus.COMPLETED.value: completed,
                },
                "completion_rate": rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and not self.projects.exists(project_id):
                raise NotFoundError("Project not found: {0}".format(project_id))

            if project_id is not None:
                scope_tasks = self.tasks.get_tasks_for_project_raw(project_id)
            else:
                scope_tasks = self.tasks.all_tasks_raw()

            user_task_map = {}
            for t in scope_tasks:
                if t.assignee_id is not None:
                    user_task_map.setdefault(t.assignee_id, []).append(t)

            rows = []
            for uid, utasks in user_task_map.items():
                total = len(utasks)
                completed = sum(1 for t in utasks if t.status == TaskStatus.COMPLETED)
                rate = completed / total if total > 0 else 0.0

                done = [
                    t for t in utasks
                    if t.status == TaskStatus.COMPLETED and t.started_at and t.completed_at
                ]
                avg_time = None
                if done:
                    times = [(t.completed_at - t.started_at).total_seconds() for t in done]
                    avg_time = sum(times) / len(times)

                ratings = self.performance.get_ratings_for(uid)
                r_count = len(ratings)
                r_avg = sum(r.score for r in ratings) / r_count if r_count > 0 else 0.0

                user_raw = self.users._users.get(uid)
                username = user_raw.username if user_raw else str(uid)

                rows.append({
                    "user_id": uid,
                    "username": username,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": rate,
                    "average_completion_time": avg_time,
                    "rating_count": r_count,
                    "rating_average": r_avg,
                })

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            if not self.users.exists(user_id):
                raise NotFoundError("User not found: {0}".format(user_id))
            user_tasks = self.tasks.get_tasks_for_assignee_raw(user_id)
            total = len(user_tasks)
            completed = sum(1 for t in user_tasks if t.status == TaskStatus.COMPLETED)
            tasks_copies = [_clone_task(t) for t in user_tasks]

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "tasks": tasks_copies,
            }

    def export_report(self, report, fmt):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat instance")
            if fmt == ReportFormat.CSV:
                return self._export_csv(report)
            return self._export_pdf(report)

    def _export_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        report_type = report.get("report_type", "")
        if report_type == ReportType.TEAM_PERFORMANCE.value:
            headers = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time",
                "rating_count", "rating_average",
            ]
            writer.writerow(headers)
            for row in report.get("rows", []):
                writer.writerow([row.get(h, "") for h in headers])
        else:
            writer.writerow(["metric", "value"])
            for k, v in report.items():
                writer.writerow([str(k), str(v)])
        return output.getvalue()

    def _export_pdf(self, report):
        lines = ["{0}: {1}".format(k, v) for k, v in report.items()]
        return _make_pdf(lines)
